from haystack import component

@component
class EscalationRouter:
    @component.output_types(has_escalated=bool, escalation_reason=str)
    def run(self, response: str, confidence: float = 0.8, keywords: list = ["urgent", "billing_issue"]):
        reason = None
        if confidence < 0.7:
            reason = "low_confidence"
        elif any(kw in response.lower() for kw in keywords):
            reason = "escalation_keywords"

        return {"has_escalated": reason is not None, "escalation_reason": reason or "none"}

import re

from haystack import component

@component
class PIIFilter:
    @component.input_types(text=str)
    @component.output_types(cleaned_text=str, entities_found=list)
    def run(self, text: str):
        patterns = [
            r'\b\d{3}-\d{3}-\d{4}\b',  # Phone
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',  # Email
            r'\b\d{16}\b'  # Credit card
        ]
        entities = []
        cleaned = text
        for pattern in patterns:
            matches = re.finditer(pattern, cleaned)
            for match in matches:
                entities.append(match.group())
                cleaned = cleaned.replace(match.group(), "[REDACTED]")
        return {"cleaned_text": cleaned, "entities_found": entities}

