from vex_sdk import VexClient
from haystack import component

@component
class VexVerifier:
    def __init__(self, vex_api_key: str, project_id: str):
        self.vex = VexClient(api_key=vex_api_key)
        self.project_id = project_id

    @component.input_types(response=str, retrieved_docs=list, query=str, customer_id=str)
    @component.output_types(approved=bool, feedback=str, score=float)
    def run(self, response: str, retrieved_docs: list, query: str, customer_id: str):
        # Define verification tests for customer support
        tests = {
            "response_accuracy": {
                "type": "semantic_similarity",
                "input": response,
                "reference": "\n".join([doc.content for doc in retrieved_docs]),
                "threshold": 0.75
            },
            "pii_filtering": {
                "type": "pii_detection",
                "input": response,
                "policy": "block"
            },
            "tone_consistency": {
                "type": "sentiment_analysis",
                "input": response,
                "target": "positive|neutral",
                "min_score": 0.6
            },
            "policy_compliance": {
                "type": "policy_check",
                "input": response,
                "rules": ["no_promises", "escalate_billing", "brand_tone"]
            }
        }

        result = self.vex.verify_suite(
            project_id=self.project_id,
            tests=tests,
            metadata={"customer_id": customer_id, "query": query}
        )

        return {
            "approved": result["pass"],
            "feedback": result["feedback"],
            "score": result["aggregate_score"]
        }
